const rows = $input.all().map(i => i.json);

const agents = ["USD", "EUR", "GOLD", "NQ", "BTC"];
const weekendBlockedAssets = ["USD", "EUR", "GOLD", "NQ"];

const nowLondon = new Date();
const londonWeekday = nowLondon.toLocaleDateString("en-US", {
  weekday: "long",
  timeZone: "Europe/London"
});

const isWeekend = ["Saturday", "Sunday"].includes(londonWeekday);

function isMarketOpen(agent) {
  if (agent === "BTC") return true;
  return !isWeekend;
}

function parseMaybeJson(value, fallback = {}) {
  if (value === null || value === undefined || value === "") return fallback;
  if (typeof value === "object") return value;

  try {
    return JSON.parse(value);
  } catch (e) {
    return fallback;
  }
}

function parseMaybeArray(value, fallback = []) {
  if (value === null || value === undefined || value === "") return fallback;
  if (Array.isArray(value)) return value;

  try {
    const parsed = JSON.parse(value);
    return Array.isArray(parsed) ? parsed : fallback;
  } catch (e) {
    return fallback;
  }
}

function toNumber(value) {
  if (value === null || value === undefined || value === "") return null;
  const n = Number(value);
  return Number.isFinite(n) ? n : null;
}

function applyWeekend24hCall(agent, calls) {
  if (isWeekend && weekendBlockedAssets.includes(agent)) {
    return {
      ...calls,
      "24h": {
        direction: "NO 24H CALL",
        conviction: null,
        reason: "Weekend rule active: this market is closed, so no 24h bias is issued.",
        status: "market_closed"
      }
    };
  }

  return calls;
}

function latestFor(agent) {
  const matches = rows
    .filter(r => r.agent_name === agent && Number(r.layer) === 1)
    .filter(r => {
      const output = parseMaybeJson(r.full_output || r.raw_agent_output, {});
      return r.direction_24h || r.call_24h_direction || output.direction_24h;
    })
    .sort((a, b) => {
      const dateA = new Date(a.created_at || a.run_time_et || 0).getTime();
      const dateB = new Date(b.created_at || b.run_time_et || 0).getTime();
      return dateB - dateA;
    });

  return matches[0] || null;
}

function emptyAgent(agent) {
  const baseCalls = {
    "24h": { direction: "PENDING", conviction: null, reason: "Awaiting data" },
    "3d": { direction: "PENDING", conviction: null, reason: "Awaiting data" },
    "current_week": { direction: "PENDING", conviction: null, reason: "Awaiting data" },
    "next_week": { direction: "PENDING", conviction: null, reason: "Awaiting data" },
    "current_month": { direction: "PENDING", conviction: null, reason: "Awaiting data" }
  };

  return {
    agent,
    status: "pending",
    market_status: isMarketOpen(agent) ? "open" : "closed",
    last_run_et: null,
    summary: `Awaiting first ${agent} agent run.`,
    calls: applyWeekend24hCall(agent, baseCalls),
    priority_timeframe: "24h",
    priority_call: applyWeekend24hCall(agent, baseCalls)["24h"],
    factor_breakdown: {},
    key_factors: [],
    warnings: [],
    reasoning_summary: "",
    score_bullish: null,
    score_bearish: null,
    score_neutral: null,
    non_neutral_count: null,
    logic_document: null,
    logic_document_version: null,
    conviction_model: {},
    timeframe_models: {},
    display_metrics: {
      bull_case: null,
      bear_case: null,
      winning_side: null,
      conviction: null,
      net_edge: null,
      directional_participation: null,
      neutral: null,
      verdict_strength: null,
      bull_case_weight: null,
      bear_case_weight: null
    },
    full_output: {}
  };
}

function outputFromRow(row) {
  return parseMaybeJson(row.full_output, parseMaybeJson(row.raw_agent_output, {}));
}

function getDirection(row, output, oldField, newField) {
  return row[oldField] || row[newField] || output[newField] || "PENDING";
}

function getConviction(row, output, oldField, newField) {
  return toNumber(row[oldField] ?? row[newField] ?? output[newField] ?? null);
}

function buildKeyFactors(factorBreakdown) {
  if (!factorBreakdown || typeof factorBreakdown !== "object" || Array.isArray(factorBreakdown)) {
    return [];
  }

  return Object.entries(factorBreakdown).map(([key, value]) => {
    if (value && typeof value === "object") {
      const signal = value.signal || "NEUTRAL";
      const weight = value.weight !== undefined ? ` [${value.weight}]` : "";
      const evidence = value.evidence ? ` — ${value.evidence}` : "";
      const reason = value.reason ? ` (${value.reason})` : "";
      return `${key}${weight}: ${signal}${evidence}${reason}`;
    }

    return `${key}: ${value}`;
  });
}

function normaliseConvictionModel(output, timeframeKey = "24h") {
  const timeframeModel = output.timeframe_models?.[timeframeKey] || {};
  const model = timeframeModel.conviction_model || output.conviction_model || {};
  const weightedScore = timeframeModel.weighted_score || output.weighted_score || {};

  const bullishArgument = toNumber(model.bullish_argument_pct);
  const bearishArgument = toNumber(model.bearish_argument_pct);
  const neutralPct = toNumber(model.neutral_evidence_pct ?? model.neutral_pct);
  const directionalParticipation = toNumber(
    model.directional_participation_pct ??
    model.active_participation_pct
  );
  const netEdge = toNumber(model.net_edge_pct);
  const finalConviction = toNumber(model.final_conviction);

  const winningSide =
    model.winning_side ||
    (
      bullishArgument !== null && bearishArgument !== null
        ? bullishArgument > bearishArgument
          ? "BULLISH"
          : bearishArgument > bullishArgument
            ? "BEARISH"
            : "TIED"
        : null
    );

  return {
    ...model,

    bullish_argument_pct: bullishArgument,
    bearish_argument_pct: bearishArgument,
    neutral_pct: neutralPct,
    neutral_evidence_pct: neutralPct,
    directional_participation_pct: directionalParticipation,
    active_participation_pct: directionalParticipation,
    net_edge_pct: netEdge,
    final_conviction: finalConviction,
    verdict_strength: model.verdict_strength || null,
    winning_side: winningSide,
    final_conviction_logic: model.final_conviction_logic || "",

    bull_case_weight: toNumber(model.bull_case_weight ?? weightedScore.bullish_weight ?? null),
    bear_case_weight: toNumber(model.bear_case_weight ?? weightedScore.bearish_weight ?? null),
    neutral_weight: toNumber(model.neutral_weight ?? weightedScore.neutral_weight ?? null),

    weighted_score: {
      bullish_weight: toNumber(weightedScore.bullish_weight ?? model.bull_case_weight ?? null),
      bearish_weight: toNumber(weightedScore.bearish_weight ?? model.bear_case_weight ?? null),
      neutral_weight: toNumber(weightedScore.neutral_weight ?? model.neutral_weight ?? null),
      active_weight: toNumber(weightedScore.active_weight ?? directionalParticipation ?? null),
      weight_margin: toNumber(weightedScore.weight_margin ?? null)
    },

    alignment: bullishArgument,
    base_conviction: finalConviction,
    participation: directionalParticipation
  };
}

function timeframeModel(output, key) {
  return output.timeframe_models?.[key] || {};
}

function callObject(row, output, key, oldDirection, newDirection, oldConviction, newConviction, oldReason, newReason) {
  const tfModel = timeframeModel(output, key);

  return {
    direction: getDirection(row, output, oldDirection, newDirection),
    conviction: getConviction(row, output, oldConviction, newConviction),
    reason:
      row[oldReason] ||
      output[newReason] ||
      tfModel.reason ||
      row.reasoning_summary ||
      output.reasoning_summary ||
      "",
    conviction_model: normaliseConvictionModel(output, key),
    weighted_score: tfModel.weighted_score || output.weighted_score || {},
    factor_breakdown: tfModel.factor_breakdown || output.factor_breakdown || {}
  };
}

function fromRow(agent, row) {
  if (!row) return emptyAgent(agent);

  const output = outputFromRow(row);
  const factorBreakdown = parseMaybeJson(row.factor_breakdown, output.factor_breakdown || {});
  const warnings = parseMaybeArray(row.warnings, output.risk_flags || output.warnings || []);

  const baseCalls = {
    "24h": callObject(
      row, output, "24h",
      "call_24h_direction", "direction_24h",
      "call_24h_conviction", "conviction_24h",
      "call_24h_reason", "reason_24h"
    ),
    "3d": callObject(
      row, output, "3d",
      "call_3d_direction", "direction_3_day",
      "call_3d_conviction", "conviction_3_day",
      "call_3d_reason", "reason_3_day"
    ),
    "current_week": callObject(
      row, output, "current_week",
      "call_current_week_direction", "direction_current_week",
      "call_current_week_conviction", "conviction_current_week",
      "call_current_week_reason", "reason_current_week"
    ),
    "next_week": callObject(
      row, output, "next_week",
      "call_next_week_direction", "direction_next_week",
      "call_next_week_conviction", "conviction_next_week",
      "call_next_week_reason", "reason_next_week"
    ),
    "current_month": callObject(
      row, output, "current_month",
      "call_current_month_direction", "direction_current_month",
      "call_current_month_conviction", "conviction_current_month",
      "call_current_month_reason", "reason_current_month"
    )
  };

  const calls = applyWeekend24hCall(agent, baseCalls);
  const priorityTimeframe = "24h";
  const priorityCall = calls[priorityTimeframe];

  const convictionModel =
    priorityCall?.status === "market_closed"
      ? {
          bullish_argument_pct: null,
          bearish_argument_pct: null,
          neutral_pct: null,
          neutral_evidence_pct: null,
          directional_participation_pct: null,
          active_participation_pct: null,
          net_edge_pct: null,
          final_conviction: null,
          verdict_strength: "MARKET_CLOSED",
          winning_side: "MARKET_CLOSED",
          final_conviction_logic: "24H priority timeframe is closed by weekend rule.",
          bull_case_weight: null,
          bear_case_weight: null,
          neutral_weight: null
        }
      : normaliseConvictionModel(output, priorityTimeframe);

  return {
    agent,
    status: "live",
    market_status: isMarketOpen(agent) ? "open" : "closed",
    last_run_et: row.run_time_et || row.created_at || null,
    summary: `${agent} Layer 1 raw call generated from sealed independent workflow.`,

    calls,
    priority_timeframe: priorityTimeframe,
    priority_call: priorityCall,

    factor_breakdown: factorBreakdown,
    key_factors: buildKeyFactors(factorBreakdown),
    warnings,
    reasoning_summary: row.reasoning_summary || output.reasoning_summary || "",

    score_bullish: toNumber(row.score_bullish ?? output.score_bullish ?? null),
    score_bearish: toNumber(row.score_bearish ?? output.score_bearish ?? null),
    score_neutral: toNumber(row.score_neutral ?? output.score_neutral ?? null),
    non_neutral_count: toNumber(output.non_neutral_count ?? null),

    logic_document: row.logic_document || output.logic_document || null,
    logic_document_version: row.logic_document_version || output.logic_document_version || null,

    conviction_model: convictionModel,
    timeframe_models: output.timeframe_models || {},

    display_metrics: {
      bull_case: convictionModel.bullish_argument_pct,
      bear_case: convictionModel.bearish_argument_pct,
      winning_side: convictionModel.winning_side,
      conviction: convictionModel.final_conviction,
      net_edge: convictionModel.net_edge_pct,
      directional_participation: convictionModel.directional_participation_pct,
      neutral: convictionModel.neutral_evidence_pct ?? convictionModel.neutral_pct,
      verdict_strength: convictionModel.verdict_strength,
      bull_case_weight: convictionModel.bull_case_weight ?? null,
      bear_case_weight: convictionModel.bear_case_weight ?? null
    },

    full_output: output
  };
}

const dashboard = {
  dashboard_meta: {
    system_timezone: "America/New_York",
    execution_clock: "07:00 ET primary run",
    last_updated_et: new Date().toISOString(),
    architecture: "Layer 1 agents are sealed independent raw signal producers. No cross-agent communication.",
    weekend_rule: "BTC remains open on weekends. USD, EUR, GOLD and NQ do not issue 24h calls on Saturday or Sunday.",
    london_weekday: londonWeekday
  },
  agents: agents.map(agent => fromRow(agent, latestFor(agent)))
};

return [
  {
    json: {
      file_content: JSON.stringify(dashboard, null, 2),
      dashboard
    }
  }
];
